/**
 * Catálogo muymuytú - Estilo Malandra
 * Minimalista · Serif · Editorial
 */

/* ==================== DESIGN TOKENS ==================== */

:root {
    --color-bg:           #efe0cc;
    --color-surface:      #f7ede0;
    --color-bg-soft:      #e5d0b8;
    --color-border:       #d4b99a;
    --color-text:         #7a3b1e;
    --color-text-muted:   #b8865a;
    --color-text-hover:   #5a2a10;
    --color-accent:       #7a3b1e;
    --color-footer-bg:    #3d1f0d;
    --color-footer-text:  rgba(255,255,255,0.5);

    --font-serif:   'Plus Jakarta Sans', 'Segoe UI', sans-serif;
    --font-sans:    'Plus Jakarta Sans', 'Segoe UI', sans-serif;

    --spacing-xs:  0.5rem;
    --spacing-sm:  1rem;
    --spacing-md:  1.5rem;
    --spacing-lg:  2.5rem;
    --spacing-xl:  4rem;

    --transition: all 0.2s ease;
    --radius-sm: 3px;
    --shadow-md: 0 4px 20px rgba(0,0,0,0.08);
    --shadow-lg: 0 12px 40px rgba(0,0,0,0.13);
}

/* ==================== BASE ==================== */

*, *::before, *::after {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: var(--font-serif);
    font-size: 15px;
    line-height: 1.6;
    background: var(--color-bg);
    color: var(--color-text);
    display: grid;
    grid-template-columns: 220px 1fr;
    grid-template-rows: auto 1fr auto;
    grid-template-areas:
        "header  header"
        "sidebar main"
        "footer  footer";
    min-height: 100vh;
}

/* ==================== HEADER ==================== */

.header,
header {
    grid-area: header;
    position: relative;
    background: var(--color-bg);
    border-bottom: 1px solid var(--color-border);
    display: flex;
    align-items: center;
    justify-content: center;
    padding: var(--spacing-lg) var(--spacing-xl);
    min-height: 120px;
}

.header__logo-link {
    display: flex;
    align-items: center;
    justify-content: center;
    text-decoration: none;
}

.header__logo {
    height: 56px;
    width: auto;
    object-fit: contain;
}

.header__brand {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.header__title {
    font-family: var(--font-sans);
    font-size: clamp(2.2rem, 5vw, 4rem);
    font-weight: 500;
    letter-spacing: 0.05em;
    text-transform: uppercase;
    color: var(--color-text);
    margin: 0;
    line-height: 1;
}

.header__dot {
    font-size: 0.7em;
    font-weight: 900;
    line-height: 0;
    vertical-align: 0.1em;
    margin-left: 0.05em;
    letter-spacing: 0;
}

.header__subtitle {
    font-family: var(--font-sans);
    font-size: 0.7rem;
    font-weight: 400;
    letter-spacing: 0.18em;
    text-transform: none;
    color: var(--color-text-muted);
    align-self: flex-end;
    margin-top: 0.55rem;
}

.header__instagram {
    position: absolute;
    top: 50%;
    right: var(--spacing-lg);
    transform: translateY(-50%);
    color: var(--color-text-muted);
    font-size: 1.3rem;
    text-decoration: none;
    transition: var(--transition);
}

.header__instagram:hover {
    color: var(--color-text);
    transform: translateY(-50%) scale(1.1);
}

/* ==================== SIDE MENU ==================== */

.side-menu {
    grid-area: sidebar;
    position: sticky;
    top: 0;
    height: 100vh;
    padding: var(--spacing-xl) var(--spacing-lg);
    background: var(--color-bg);
    border-right: 1px solid var(--color-border);
    display: flex;
    flex-direction: column;
    gap: 2px;
}

.side-menu__item {
    position: relative;
}

/* ==================== FILTER BUTTONS - ESTILO TEXTO PLANO ==================== */

.filter-btn {
    background: none;
    border: none;
    padding: 0.45rem 0;
    width: 100%;
    text-align: left;
    font-family: var(--font-serif);
    font-size: 0.95rem;
    font-style: normal;
    font-weight: 400;
    color: var(--color-text-muted);
    cursor: pointer;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    transition: var(--transition);
    display: flex;
    align-items: center;
    gap: 0.5rem;
    position: relative;
}

.filter-btn::before {
    content: '';
    display: inline-block;
    width: 0;
    height: 1px;
    background: var(--color-text);
    transition: width 0.2s ease;
    flex-shrink: 0;
}

.filter-btn:hover {
    color: var(--color-text);
    transform: none;
    box-shadow: none;
}

.filter-btn:hover::before {
    width: 14px;
}

.filter-btn.active {
    color: var(--color-text);
    font-weight: 400;
}

.filter-btn.active::before {
    width: 14px;
}

.filter-btn:focus {
    outline: none;
    color: var(--color-text);
}

/* Subcategorías */
.filter-btn--sub {
    font-size: 0.82rem;
    color: var(--color-text-muted);
    padding: 0.35rem 0;
    width: 100%;
    text-align: left;
    letter-spacing: 0.03em;
}

.filter-btn--sub::before {
    background: var(--color-text-muted);
}

.filter-btn--sub:hover {
    color: var(--color-text);
}

.filter-btn--sub:hover::before {
    width: 10px;
}

.filter-btn--sub.active {
    color: var(--color-text);
}

.filter-btn--sub.active::before {
    width: 10px;
    background: var(--color-text);
}

/* Submenu flotante */
.side-menu__submenu {
    position: absolute;
    left: calc(100% + 16px);
    top: 0;
    min-width: 140px;
    background: var(--color-surface);
    border: 1px solid var(--color-border);
    border-radius: var(--radius-sm);
    box-shadow: var(--shadow-md);
    padding: var(--spacing-sm);
    display: flex;
    flex-direction: column;
    gap: 2px;
    z-index: 100;
    opacity: 0;
    pointer-events: none;
    transform: translateX(-6px);
    transition: var(--transition);
}

.side-menu__item--has-submenu:hover .side-menu__submenu,
.side-menu__item--has-submenu:focus-within .side-menu__submenu {
    opacity: 1;
    pointer-events: auto;
    transform: translateX(0);
}

/* ==================== MAIN ==================== */

.main, main {
    grid-area: main;
    padding: var(--spacing-lg);
    position: relative;
    background-color: var(--color-bg);
    background-image:
        linear-gradient(rgba(239, 224, 204, 0.15), rgba(239, 224, 204, 0.15)),
        url('../images/fondo.jpg');
    background-size: 75%;
    background-position: center 15%;
    background-repeat: no-repeat;
}

/* ==================== PRODUCTS GRID ==================== */

.products-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
    gap: var(--spacing-md);
}

/* ==================== PRODUCT CARD ==================== */

.product-card {
    background: var(--color-surface);
    overflow: hidden;
    cursor: pointer;
    transition: var(--transition);
}

.product-card:hover {
    transform: translateY(-4px);
}

.product-card.hidden {
    display: none;
}

.product-card__image,
.product-image {
    width: 100%;
    aspect-ratio: 3 / 4;
    overflow: hidden;
    background: var(--color-bg-soft);
    display: flex;
    align-items: center;
    justify-content: center;
}

.product-card__image img,
.product-image img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.5s ease;
}

.product-card:hover .product-image img {
    transform: scale(1.04);
}

/* ==================== FOOTER ==================== */

.footer, footer {
    grid-area: footer;
    background: var(--color-footer-bg);
    color: var(--color-footer-text);
    text-align: center;
    padding: var(--spacing-md);
    font-family: var(--font-sans);
    font-size: 0.72rem;
    letter-spacing: 0.15em;
    text-transform: uppercase;
}

/* ==================== UTILITY ==================== */

.u-hidden { display: none !important; }

.u-sr-only {
    position: absolute;
    width: 1px; height: 1px;
    padding: 0; margin: -1px;
    overflow: hidden;
    clip: rect(0,0,0,0);
    white-space: nowrap;
    border-width: 0;
}

/* ==================== LIGHTBOX ==================== */

.lightbox {
    position: fixed;
    inset: 0;
    background: rgba(0,0,0,0.95);
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 1000;
    animation: lightbox-in 0.2s ease;
}

@keyframes lightbox-in {
    from { opacity: 0; }
    to   { opacity: 1; }
}

.lightbox--hidden { display: none; }

.lightbox__image {
    max-width: 88vw;
    max-height: 88vh;
    object-fit: contain;
}

.lightbox__close {
    position: fixed;
    top: var(--spacing-md);
    right: var(--spacing-md);
    background: none;
    border: 1px solid rgba(255,255,255,0.3);
    border-radius: 50%;
    width: 40px; height: 40px;
    font-size: 0.9rem;
    color: rgba(255,255,255,0.7);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: var(--transition);
}

.lightbox__close:hover {
    background: rgba(255,255,255,0.1);
    color: #fff;
}

/* ==================== RESPONSIVE ==================== */

@media (max-width: 900px) {
    body {
        grid-template-columns: 1fr;
        grid-template-areas:
            "header"
            "sidebar"
            "main"
            "footer";
    }

    .side-menu {
        position: static;
        height: auto;
        flex-direction: row;
        flex-wrap: wrap;
        justify-content: center;
        border-right: none;
        border-bottom: 1px solid var(--color-border);
        padding: var(--spacing-sm) var(--spacing-md);
        gap: 0 var(--spacing-md);
    }

    .side-menu__btn {
        width: auto;
    }

    .side-menu__submenu {
        left: 50%;
        top: calc(100% + 8px);
        transform: translate(-50%, -6px);
    }

    .side-menu__item--has-submenu:hover .side-menu__submenu,
    .side-menu__item--has-submenu:focus-within .side-menu__submenu {
        transform: translate(-50%, 0);
    }
}

@media (max-width: 480px) {
    .header__title, header h1 {
        font-size: 1.1rem;
        letter-spacing: 0.35em;
    }
}

/* ==================== PRINT ==================== */

@media print {
    .side-menu, footer { display: none; }
    .product-card { break-inside: avoid; }
}

